/**
 * Scores Schema
 *
 * A new unified scoring system that replaces the results + sets tables.
 * Designed for efficient sorting and querying.
 */

import { createId } from "@paralleldrive/cuid2"
import { relations } from "drizzle-orm"
import {
  boolean,
  datetime,
  index,
  int,
  mysqlTable,
  text,
  uniqueIndex,
  varchar,
} from "drizzle-orm/mysql-core"
import { commonColumns } from "./common"
import { scalingLevelsTable } from "./scaling"
import { teamTable } from "./teams"
import { userTable } from "./users"
import { workouts } from "./workouts"

// ID generators
export const createScoreId = () => `score_${createId()}`
export const createScoreRoundId = () => `scrd_${createId()}`
export const createScoreVerificationLogId = () => `svlog_${createId()}`

// Score status values for the new scores table
// This is a subset focused on competition/scoring context
const SCORE_STATUS_NEW_VALUES = ["scored", "cap", "dq", "withdrawn"] as const
export type ScoreStatusNew = (typeof SCORE_STATUS_NEW_VALUES)[number]

/**
 * Core scores table
 *
 * Stores workout results with encoded integer values for efficient sorting.
 * Replaces the old results + sets tables.
 */
export const scoresTable = mysqlTable(
  "scores",
  {
    ...commonColumns,
    id: varchar({ length: 255 }).primaryKey().$defaultFn(createScoreId),

    // Ownership
    userId: varchar({ length: 255 }).notNull(),
    teamId: varchar({ length: 255 }).notNull(),

    // What was scored
    workoutId: varchar({ length: 255 }).notNull(),
    competitionEventId: varchar({ length: 255 }), // NULL for personal logs
    scheduledWorkoutInstanceId: varchar({ length: 255 }),

    // Score classification
    scheme: varchar({ length: 255 }).notNull(),
    scoreType: varchar({ length: 255 }).notNull().default("max"),

    // Primary score (encoded as integer based on scheme)
    // Time: milliseconds, Rounds+Reps: rounds*100000+reps, Load: grams, Distance: mm
    scoreValue: int(),

    // Tiebreak
    tiebreakScheme: varchar({ length: 255 }),
    tiebreakValue: int(),

    // Time cap handling (for time-with-cap workouts)
    timeCapMs: int(),
    // Note: secondaryScheme removed - when capped, score is always reps
    secondaryValue: int(), // reps completed if capped

    // Status & sorting
    status: varchar({ length: 255 }).notNull().default("scored"),
    statusOrder: int().notNull().default(0), // 0=scored, 1=cap, 2=dq, 3=withdrawn
    // Compound sort key: encodes status + normalized score for single-column sorting
    sortKey: varchar({ length: 255 }),

    // Scaling
    scalingLevelId: varchar({ length: 255 }),
    asRx: boolean().notNull().default(false),

    // Metadata
    notes: text(),
    // When the workout was performed (Unix timestamp ms)
    recordedAt: datetime().notNull(),

    // Verification (organizer review for online competitions)
    // null = unreviewed, "verified" = confirmed, "adjusted" = overridden, "invalid" = zeroed
    verificationStatus: varchar({ length: 20 }),
    verifiedAt: datetime(),
    verifiedByUserId: varchar({ length: 255 }),

    // Penalty classification (denormalized from verification log for leaderboard/athlete display)
    // null = no penalty, "minor" | "major"
    penaltyType: varchar("penalty_type", { length: 20 }),
    // The percentage deduction applied (0-100)
    penaltyPercentage: int("penalty_percentage"),
    // Total no-rep count from review notes
    noRepCount: int("no_rep_count"),
  },
  (table) => [
    // User's scores, ordered by date
    index("idx_scores_user").on(table.userId, table.recordedAt),
    // Leaderboard queries: workout + team, sorted by status and score
    index("idx_scores_workout").on(
      table.workoutId,
      table.teamId,
      table.statusOrder,
      table.sortKey,
    ),
    // Competition leaderboards
    index("idx_scores_competition").on(
      table.competitionEventId,
      table.statusOrder,
      table.sortKey,
    ),
    // Scheduled workout lookup
    index("idx_scores_scheduled").on(table.scheduledWorkoutInstanceId),
    // Unique constraint for competition scores (one score per user per event)
    uniqueIndex("idx_scores_competition_user_unique").on(
      table.competitionEventId,
      table.userId,
    ),
  ],
)

/**
 * Score rounds table
 *
 * Stores individual rounds/sets within a score.
 * For multi-round workouts like "10x3 Back Squat" or "3 rounds for time".
 */
export const scoreRoundsTable = mysqlTable(
  "score_rounds",
  {
    id: varchar({ length: 255 }).primaryKey().$defaultFn(createScoreRoundId),
    scoreId: varchar({ length: 255 }).notNull(),

    // Round ordering (1-indexed)
    roundNumber: int().notNull(),

    // The value for this round (encoded based on parent score's scheme)
    value: int().notNull(),

    // Optional: different scheme per round (rare, but possible)
    schemeOverride: varchar({ length: 255 }),

    // Status for this specific round
    status: varchar({ length: 255 }),

    // For time-capped rounds
    secondaryValue: int(),

    // Metadata
    notes: text(),
    createdAt: datetime()
      .$defaultFn(() => new Date())
      .notNull(),
  },
  (table) => [
    // Lookup rounds for a score
    index("idx_score_rounds_score").on(table.scoreId, table.roundNumber),
    // Unique constraint on score + round number
    uniqueIndex("idx_score_rounds_unique").on(table.scoreId, table.roundNumber),
  ],
)

// Relations
export const scoresRelations = relations(scoresTable, ({ one, many }) => ({
  user: one(userTable, {
    fields: [scoresTable.userId],
    references: [userTable.id],
  }),
  team: one(teamTable, {
    fields: [scoresTable.teamId],
    references: [teamTable.id],
  }),
  workout: one(workouts, {
    fields: [scoresTable.workoutId],
    references: [workouts.id],
  }),
  scalingLevel: one(scalingLevelsTable, {
    fields: [scoresTable.scalingLevelId],
    references: [scalingLevelsTable.id],
  }),
  rounds: many(scoreRoundsTable),
}))

export const scoreRoundsRelations = relations(scoreRoundsTable, ({ one }) => ({
  score: one(scoresTable, {
    fields: [scoreRoundsTable.scoreId],
    references: [scoresTable.id],
  }),
}))

/**
 * Score verification log table
 *
 * Append-only audit trail of every organizer verify/adjust action on a score.
 * For "adjusted" entries, captures the original values before overwrite so
 * the athlete's claimed score is never permanently lost.
 */
export const scoreVerificationLogsTable = mysqlTable(
  "score_verification_logs",
  {
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(createScoreVerificationLogId),

    // The score that was acted on
    scoreId: varchar({ length: 255 }).notNull(),

    // Competition context (denormalized for easy querying, null for non-competition scores)
    competitionId: varchar({ length: 255 }),
    trackWorkoutId: varchar({ length: 255 }),

    // The athlete who owns the score
    athleteUserId: varchar({ length: 255 }).notNull(),

    // What the organizer did
    action: varchar({ length: 20 }).notNull(), // "verified" | "adjusted" | "invalid"

    // Values before adjustment (null for "verified" action)
    originalScoreValue: int(),
    originalStatus: varchar({ length: 50 }),
    originalSecondaryValue: int(),
    originalTiebreakValue: int(),

    // Values after adjustment (null for "verified" action)
    newScoreValue: int(),
    newStatus: varchar({ length: 50 }),
    newSecondaryValue: int(),
    newTiebreakValue: int(),

    // Penalty audit trail (snapshot at time of action)
    penaltyType: varchar("penalty_type", { length: 20 }),
    penaltyPercentage: int("penalty_percentage"),
    noRepCount: int("no_rep_count"),

    // Who did it and when
    performedByUserId: varchar({ length: 255 }).notNull(),
    performedAt: datetime().notNull(),
  },
  (table) => [
    // Look up all log entries for a score
    index("idx_svlog_score").on(table.scoreId),
    // Look up all actions by an organizer
    index("idx_svlog_performer").on(table.performedByUserId, table.performedAt),
  ],
)

export const scoreVerificationLogsRelations = relations(
  scoreVerificationLogsTable,
  ({ one }) => ({
    score: one(scoresTable, {
      fields: [scoreVerificationLogsTable.scoreId],
      references: [scoresTable.id],
    }),
    performedBy: one(userTable, {
      fields: [scoreVerificationLogsTable.performedByUserId],
      references: [userTable.id],
    }),
  }),
)

// Type exports
export type Score = typeof scoresTable.$inferSelect
export type ScoreInsert = typeof scoresTable.$inferInsert
export type ScoreRound = typeof scoreRoundsTable.$inferSelect
export type ScoreRoundInsert = typeof scoreRoundsTable.$inferInsert

        existingScore.scheme as WorkoutScheme,
        { compact: false },
      )
    }

    return {
      scoreId: existingScore.id,
      scoreValue: existingScore.scoreValue,
      displayScore,
      status: existingScore.status,
      secondaryValue: existingScore.secondaryValue,
      tiebreakValue: existingScore.tiebreakValue,
      submittedAt: existingScore.recordedAt,
    }
  })

/**
 * Submit or update an athlete's score for an event
 */
export const submitAthleteScoreFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => submitScoreInputSchema.parse(data))
  .handler(
    async ({
      data,
    }): Promise<{
      success: boolean
      scoreId: string
      message: string
    }> => {
      const session = await getSessionFromCookie()
      if (!session?.userId) {
        logWarning({
          message: "[AthleteScore] Submission denied - not authenticated",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
          },
        })
        throw new Error("Not authenticated")
      }

      const db = getDb()

      // Update request context
      updateRequestContext({ userId: session.userId })
      addRequestContextAttribute("competitionId", data.competitionId)
      addRequestContextAttribute("trackWorkoutId", data.trackWorkoutId)

      logInfo({
        message: "[AthleteScore] Score submission started",
        attributes: {
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
          userId: session.userId,
          status: data.status,
        },
      })

      // 1. Check that user is registered for this competition
      const [registration] = await db
        .select({
          id: competitionRegistrationsTable.id,
          divisionId: competitionRegistrationsTable.divisionId,
        })
        .from(competitionRegistrationsTable)
        .where(
          and(
            eq(competitionRegistrationsTable.eventId, data.competitionId),
            eq(competitionRegistrationsTable.userId, session.userId),
            ne(
              competitionRegistrationsTable.status,
              REGISTRATION_STATUS.REMOVED,
            ),
          ),
        )
        .limit(1)

      if (!registration) {
        logWarning({
          message: "[AthleteScore] Submission denied - not registered",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
          },
        })
        throw new Error("You are not registered for this competition")
      }

      addRequestContextAttribute("registrationId", registration.id)

      // 2. Check submission window
      const windowStatus = await checkSubmissionWindow(
        data.competitionId,
        data.trackWorkoutId,
      )

      if (!windowStatus.isOpen) {
        logWarning({
          message: "[AthleteScore] Submission window blocked",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
            reason: windowStatus.reason,
            opensAt: windowStatus.opensAt,
            closesAt: windowStatus.closesAt,
          },
        })
        throw new Error(windowStatus.reason || "Submission window is not open")
      }

      // 3. Get workout info for proper encoding
      const [trackWorkout] = await db
        .select({
          workoutId: trackWorkoutsTable.workoutId,
          trackId: trackWorkoutsTable.trackId,
        })
        .from(trackWorkoutsTable)
        .where(eq(trackWorkoutsTable.id, data.trackWorkoutId))
        .limit(1)

      if (!trackWorkout) {
        throw new Error("Event not found")
      }

      const [workout] = await db
        .select({
          scheme: workouts.scheme,
          scoreType: workouts.scoreType,
          tiebreakScheme: workouts.tiebreakScheme,
          timeCap: workouts.timeCap,
        })
        .from(workouts)
        .where(eq(workouts.id, trackWorkout.workoutId))
        .limit(1)

      if (!workout) {
        throw new Error("Workout not found")
      }

      const scheme = workout.scheme as WorkoutScheme
      const scoreType =
        (workout.scoreType as ScoreType) || getDefaultScoreType(scheme)

      // 4. Parse and validate the score
      const parseResult = parseScore(data.score, scheme)
      if (!parseResult.isValid) {
        logWarning({
          message: "[AthleteScore] Invalid score format",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
            score: data.score,
            scheme,
            error: parseResult.error,
          },
        })
        throw new Error(
          `Invalid score format: ${parseResult.error || "Please check your entry"}`,
        )
      }

      // Encode the score
      let encodedValue: number | null = encodeScore(data.score, scheme)

      // Handle CAP status for time-with-cap workouts
      if (
        data.status === "cap" &&
        scheme === "time-with-cap" &&
        workout.timeCap
      ) {
        encodedValue = workout.timeCap * 1000 // Time cap in milliseconds
      }

      // Parse secondary score (reps at cap)
      let secondaryValue: number | null = null
      if (data.secondaryScore && data.status === "cap") {
        const parsed = Number.parseInt(data.secondaryScore.trim(), 10)
        if (!Number.isNaN(parsed) && parsed >= 0) {
          secondaryValue = parsed
        }
      }

      // Parse tiebreak score
      let tiebreakValue: number | null = null
      if (data.tiebreakScore && workout.tiebreakScheme) {
        tiebreakValue = encodeScore(
          data.tiebreakScore,
          workout.tiebreakScheme as WorkoutScheme,
        )
      }

      // Time cap in milliseconds
      const timeCapMs = workout.timeCap ? workout.timeCap * 1000 : null

      // Compute sort key
      const sortKey =
        encodedValue !== null
          ? computeSortKey({
              value: encodedValue,
              status: data.status,
              scheme,
              scoreType,
            })
          : null

      // 5. Get teamId from track
      const [track] = await db
        .select({
          ownerTeamId: programmingTracksTable.ownerTeamId,
        })
        .from(programmingTracksTable)
        .where(eq(programmingTracksTable.id, trackWorkout.trackId))
        .limit(1)

      if (!track?.ownerTeamId) {
        throw new Error("Could not determine team ownership")
      }

      // 6. Upsert the score
      await db
        .insert(scoresTable)
        .values({
          userId: session.userId,
          teamId: track.ownerTeamId,
          workoutId: trackWorkout.workoutId,
          competitionEventId: data.trackWorkoutId,
          scheme,
          scoreType,
          scoreValue: encodedValue,
          status: data.status,
          statusOrder: getStatusOrder(data.status),
          sortKey: sortKey ? sortKeyToString(sortKey) : null,
          tiebreakScheme: (workout.tiebreakScheme as TiebreakScheme) ?? null,
          tiebreakValue,
          timeCapMs,
          secondaryValue,
          scalingLevelId: registration.divisionId,
          asRx: true,
          recordedAt: new Date(),
        })
        .onDuplicateKeyUpdate({
          set: {
            scoreValue: encodedValue,
            status: data.status,
            statusOrder: getStatusOrder(data.status),
            sortKey: sortKey ? sortKeyToString(sortKey) : null,
            tiebreakScheme: (workout.tiebreakScheme as TiebreakScheme) ?? null,
            tiebreakValue,
            timeCapMs,
            secondaryValue,
            scalingLevelId: registration.divisionId,
            updatedAt: new Date(),
          },
        })

      // Get the final score ID
      const [finalScore] = await db
        .select({ id: scoresTable.id })
        .from(scoresTable)
        .where(
          and(
            eq(scoresTable.competitionEventId, data.trackWorkoutId),
            eq(scoresTable.userId, session.userId),
          ),
        )
        .limit(1)

      if (!finalScore) {
        logError({
          message: "[AthleteScore] Failed to retrieve score after upsert",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
          },
        })
        throw new Error("Failed to save score")
      }

      addRequestContextAttribute("scoreId", finalScore.id)
      logEntityUpdated({
        entity: "athleteScore",
        id: finalScore.id,
        attributes: {
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
          userId: session.userId,
          registrationId: registration.id,
          status: data.status,
        },
      })

      logInfo({
        message: "[AthleteScore] Score submitted successfully",
        attributes: {
          scoreId: finalScore.id,
          competitionId: data.competitionId,

export type RegistrationStatus =
  (typeof REGISTRATION_STATUS)[keyof typeof REGISTRATION_STATUS]

// Competition Registrations Table
// Tracks athlete registrations for competitions
export const competitionRegistrationsTable = mysqlTable(
  "competition_registrations",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createCompetitionRegistrationId())
      .notNull(),
    // The competition this registration is for
    eventId: varchar({ length: 255 }).notNull(),
    // The user who registered (captain for team registrations)
    userId: varchar({ length: 255 }).notNull(),
    // The team membership created in the competition_event team
    teamMemberId: varchar({ length: 255 }).notNull(),
    // The division (scaling level) the athlete is competing in
    divisionId: varchar({ length: 255 }),
    // When the athlete registered
    registeredAt: datetime().notNull(),
    // Registration status: active = participating, removed = soft-deleted by organizer
    status: varchar({ length: 20 })
      .$type<RegistrationStatus>()
      .default("active")
      .notNull(),
    // Team info (NULL for individual registrations)
    teamName: varchar({ length: 255 }),
    // Who created the registration (same as userId for individuals)
    captainUserId: varchar({ length: 255 }),
    // For team registrations, the athlete team (competition_team type)
    // NULL for individual registrations (teamSize=1)
    athleteTeamId: varchar({ length: 255 }),
    // Pending teammates stored as JSON until they accept
    // Format: [{ email, firstName?, lastName?, affiliateName? }, ...]
    pendingTeammates: text(), // JSON array
    // Metadata as JSON (flexible for future expansion)
    metadata: text(), // JSON: { notes: "..." }

    // Commerce: Payment tracking
    // Reference to commerce_purchase (no FK to avoid circular deps - relation defined separately)
    commercePurchaseId: varchar({ length: 255 }),
    // Payment status: FREE | PENDING_PAYMENT | PAID | FAILED
    paymentStatus: varchar({ length: 20 }),
    // When payment was completed
    paidAt: datetime(),
  },
  (table) => [
    // One user can only register once per division per competition
    uniqueIndex("competition_registrations_event_user_division_idx").on(
      table.eventId,
      table.userId,
      table.divisionId,
    ),
    index("competition_registrations_user_idx").on(table.userId),
    index("competition_registrations_event_idx").on(table.eventId),
    index("competition_registrations_division_idx").on(table.divisionId),
    index("competition_registrations_captain_idx").on(table.captainUserId),
    index("competition_registrations_athlete_team_idx").on(table.athleteTeamId),
    index("competition_registrations_purchase_idx").on(
      table.commercePurchaseId,
    ),
    index("competition_registrations_status_idx").on(
      table.eventId,
      table.status,
    ),
  ],
)

// Competition Venues Table
// Floors/areas for heat scheduling (e.g., "Main Floor", "Outside Rig")
export const competitionVenuesTable = mysqlTable(
  "competition_venues",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createCompetitionVenueId())

/**
 * Athlete Score Submission Server Functions
 *
 * Server functions for athletes to submit their own scores in online competitions.
 * Includes validation for submission windows and score format based on workout scheme.
 *
 * OBSERVABILITY:
 * - All athlete score submissions are logged with user and event IDs
 * - Submission window status checks are logged
 * - Validation failures tracked for debugging
 */

import { createServerFn } from "@tanstack/react-start"
import { and, eq, ne } from "drizzle-orm"
import { z } from "zod"
import { getDb } from "@/db"
import {
  addRequestContextAttribute,
  logEntityUpdated,
  logError,
  logInfo,
  logWarning,
  updateRequestContext,
} from "@/lib/logging"
import {
  competitionEventsTable,
  competitionRegistrationsTable,
  competitionsTable,
  REGISTRATION_STATUS,
} from "@/db/schemas/competitions"
import {
  programmingTracksTable,
  trackWorkoutsTable,
} from "@/db/schemas/programming"
import { scoresTable } from "@/db/schemas/scores"
import type { TiebreakScheme } from "@/db/schemas/workouts"
import { workouts } from "@/db/schemas/workouts"
import {
  computeSortKey,
  encodeScore,
  getDefaultScoreType,
  parseScore,
  type ScoreType,
  STATUS_ORDER,
  sortKeyToString,
  type WorkoutScheme,
} from "@/lib/scoring"
import { getSessionFromCookie } from "@/utils/auth"

// ============================================================================
// Types
// ============================================================================

export interface AthleteScoreSubmission {
  trackWorkoutId: string
  score: string
  status: "scored" | "cap"
  /** Secondary score (reps at cap) for time-capped workouts */
  secondaryScore?: string
  /** Tiebreak score if applicable */
  tiebreakScore?: string
}

export interface SubmissionWindowStatus {
  isOpen: boolean
  opensAt: string | null
  closesAt: string | null
  reason?: string
}

export interface AthleteEventScore {
  scoreId: string | null
  scoreValue: number | null
  displayScore: string | null
  status: string | null
  secondaryValue: number | null
  tiebreakValue: number | null
  submittedAt: Date | null
}

// ============================================================================
// Input Schemas
// ============================================================================

const submitScoreInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
  score: z.string().min(1, "Score is required"),
  status: z.enum(["scored", "cap"]),
  secondaryScore: z.string().optional(),
  tiebreakScore: z.string().optional(),
})

const getScoreInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
})

const getSubmissionWindowInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
})

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Map status to the simplified type for scores table.
 */
function getStatusOrder(status: "scored" | "cap"): number {
  switch (status) {
    case "scored":
      return STATUS_ORDER.scored
    case "cap":
      return STATUS_ORDER.cap
    default:
      return STATUS_ORDER.scored
  }
}

/**
 * Check if current time is within the event's submission window.
 */
async function checkSubmissionWindow(
  competitionId: string,
  trackWorkoutId: string,
): Promise<SubmissionWindowStatus> {
  const db = getDb()

"use client"

import { useServerFn } from "@tanstack/react-start"
import { AlertCircle, Check, Clock, Loader2, Trophy } from "lucide-react"
import { useEffect, useState } from "react"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import type { ScoreType, WorkoutScheme } from "@/db/schemas/workouts"
import { type ParseResult, parseScore } from "@/lib/scoring"
import { cn } from "@/lib/utils"
import {
  type AthleteEventScore,
  getAthleteEventScoreFn,
  getEventWorkoutDetailsFn,
  getSubmissionWindowStatusFn,
  type SubmissionWindowStatus,
  submitAthleteScoreFn,
} from "@/server-fns/athlete-score-fns"

interface AthleteScoreSubmissionProps {
  competitionId: string
  trackWorkoutId: string
  competitionTimezone?: string | null
}

function formatSubmissionTime(
  isoString: string,
  timezone?: string | null,
): string {
  const date = new Date(isoString)
  return new Intl.DateTimeFormat("en-US", {
    weekday: "short",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    timeZone: timezone ?? undefined,
  }).format(date)
}

function getSchemeLabel(scheme: WorkoutScheme): string {
  switch (scheme) {
    case "time":
    case "time-with-cap":
      return "Time"
    case "rounds-reps":
      return "Rounds + Reps"
    case "reps":
      return "Reps"
    case "load":
      return "Load (lbs)"
    case "calories":
      return "Calories"
    case "meters":
      return "Meters"
    case "feet":
      return "Feet"
    case "points":
      return "Points"
    case "emom":
      return "Time"
    case "pass-fail":
      return "Rounds Passed"
    default:
      return "Score"
  }
}

function getPlaceholder(scheme: WorkoutScheme): string {
  switch (scheme) {
    case "time":
    case "time-with-cap":
    case "emom":
      return "e.g., 5:30 or 330"
    case "rounds-reps":
      return "e.g., 5+12 or 5.12"
    case "reps":
      return "e.g., 150"
    case "load":
      return "e.g., 225"
    case "calories":
      return "e.g., 50"
    case "meters":
      return "e.g., 1000"
    case "feet":
      return "e.g., 3000"
    case "points":
      return "e.g., 100"
    case "pass-fail":
      return "Rounds passed"
    default:
      return "Enter score"
  }
}

function getHelpText(scheme: WorkoutScheme, timeCap?: number | null): string {
  switch (scheme) {
    case "time":
      return "Enter as minutes:seconds (5:30) or total seconds (330)"
    case "time-with-cap":
      return timeCap
        ? `Enter as minutes:seconds (5:30) or total seconds. Time cap: ${Math.floor(timeCap / 60)}:${String(timeCap % 60).padStart(2, "0")}`
        : "Enter as minutes:seconds (5:30) or total seconds"
    case "rounds-reps":
      return "Enter as rounds+reps (5+12) or rounds.reps (5.12)"
    case "emom":
      return "Enter as minutes:seconds or total seconds"
    default:
      return ""
  }
}

export function AthleteScoreSubmission({
  competitionId,
  trackWorkoutId,
  competitionTimezone,
}: AthleteScoreSubmissionProps) {
  const [windowStatus, setWindowStatus] =
    useState<SubmissionWindowStatus | null>(null)
  const [existingScore, setExistingScore] = useState<AthleteEventScore | null>(
    null,
  )
  const [workoutDetails, setWorkoutDetails] = useState<{
    workoutId: string
    name: string
    scheme: WorkoutScheme
    scoreType: ScoreType | null
    timeCap: number | null
    tiebreakScheme: string | null
    repsPerRound: number | null
  } | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  // Form state
  const [scoreInput, setScoreInput] = useState("")
  const [status, setStatus] = useState<"scored" | "cap">("scored")
  const [secondaryScore, setSecondaryScore] = useState("")
  const [tiebreakScore, setTiebreakScore] = useState("")
  const [parseResult, setParseResult] = useState<ParseResult | null>(null)
  const [submitting, setSubmitting] = useState(false)
  const [submitSuccess, setSubmitSuccess] = useState(false)

  const submitScore = useServerFn(submitAthleteScoreFn)

  // Load initial data
  useEffect(() => {
    async function loadData() {
      setLoading(true)
      setError(null)
      try {
        const [windowRes, scoreRes, workoutRes] = await Promise.all([
          getSubmissionWindowStatusFn({
            data: { competitionId, trackWorkoutId },
          }),
          getAthleteEventScoreFn({
            data: { competitionId, trackWorkoutId },
          }),
          getEventWorkoutDetailsFn({
            data: { competitionId, trackWorkoutId },
          }),
        ])

        setWindowStatus(windowRes)
        setExistingScore(scoreRes)
        setWorkoutDetails(workoutRes)

        // Pre-fill form if there's an existing score
        if (scoreRes.displayScore) {
          setScoreInput(scoreRes.displayScore)
          setStatus((scoreRes.status as "scored" | "cap") || "scored")
          if (scoreRes.secondaryValue !== null) {
            setSecondaryScore(String(scoreRes.secondaryValue))
          }
        }
      } catch (err) {
        setError(
          err instanceof Error ? err.message : "Failed to load submission data",
        )
      } finally {
        setLoading(false)
      }
    }

    loadData()
  }, [competitionId, trackWorkoutId])

  // Parse score input
  useEffect(() => {
    if (!workoutDetails || !scoreInput.trim()) {
      setParseResult(null)
      return
    }

    const result = parseScore(scoreInput, workoutDetails.scheme)
    setParseResult(result)
  }, [scoreInput, workoutDetails])

  const handleSubmit = async () => {
    if (!workoutDetails) return

    setSubmitting(true)
    setSubmitSuccess(false)
    setError(null)

    try {
      await submitScore({
        data: {
          competitionId,
          trackWorkoutId,
          score: scoreInput,
          status,
          secondaryScore: secondaryScore || undefined,
          tiebreakScore: tiebreakScore || undefined,
        },
      })

      setSubmitSuccess(true)
      // Refresh existing score
      const scoreRes = await getAthleteEventScoreFn({
        data: { competitionId, trackWorkoutId },
      })
      setExistingScore(scoreRes)

      // Clear success message after 3 seconds
      setTimeout(() => setSubmitSuccess(false), 3000)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to submit score")
    } finally {
      setSubmitting(false)
    }
  }

"use client"

