      POST: async ({ request }: { request: Request }) => {
        const origin = request.headers.get("Origin")
        const headers = { "Content-Type": "application/json", ...corsHeaders(origin) }

        const session = await getSessionFromBearerOrCookie(request)
        if (!session?.userId) {
